import{_ as n,o as t,c as i,ag as a}from"./chunks/framework.CvgP6Fyv.js";const h=JSON.parse('{"title":"Teambeheer","description":"","frontmatter":{},"headers":[],"relativePath":"nl/settings/team.md","filePath":"nl/settings/team.md"}'),r={name:"nl/settings/team.md"};function l(o,e,s,g,d,c){return t(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="teambeheer" tabindex="-1">Teambeheer <a class="header-anchor" href="#teambeheer" aria-label="Permalink to &quot;Teambeheer&quot;">​</a></h1><p>Nodig teamleden uit, wijs rollen toe en bepaal wie toegang heeft tot wat in je werkruimte.</p><h2 id="teamleden-uitnodigen" tabindex="-1">Teamleden uitnodigen <a class="header-anchor" href="#teamleden-uitnodigen" aria-label="Permalink to &quot;Teamleden uitnodigen&quot;">​</a></h2><ol><li>Ga naar <strong>Instellingen &gt; Team</strong> of <strong>Bedrijf &gt; Teamleden</strong></li><li>Klik op <strong>Lid uitnodigen</strong></li><li>Vul het <strong>e-mailadres</strong> van de persoon in</li><li>Kies een <strong>rol</strong> (zie hieronder)</li><li>Klik op <strong>Uitnodiging versturen</strong></li></ol><p>De genodigde ontvangt een e-mail met een link om deel te nemen aan je werkruimte. Als ze nog geen MyCompanyDesk-account hebben, kunnen ze er een aanmaken tijdens het proces.</p><h2 id="rollen" tabindex="-1">Rollen <a class="header-anchor" href="#rollen" aria-label="Permalink to &quot;Rollen&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Rol</th><th>Beschrijving</th></tr></thead><tbody><tr><td><strong>Admin</strong></td><td>Volledige toegang tot alles, inclusief team- en factureringsbeheer</td></tr><tr><td><strong>Lid</strong></td><td>Toegang tot toegewezen functies, kan geen team of facturering beheren</td></tr><tr><td><strong>Accountant</strong></td><td>Alleen-lezen toegang met specifieke boekhoudweergaven</td></tr></tbody></table><h3 id="admin" tabindex="-1">Admin <a class="header-anchor" href="#admin" aria-label="Permalink to &quot;Admin&quot;">​</a></h3><p>Admins kunnen:</p><ul><li>Teamleden beheren (uitnodigen, verwijderen, rollen wijzigen)</li><li>Facturerings- en abonnementsinstellingen openen</li><li>Bedrijfsinstellingen configureren</li><li>Alle functies openen</li></ul><h3 id="lid" tabindex="-1">Lid <a class="header-anchor" href="#lid" aria-label="Permalink to &quot;Lid&quot;">​</a></h3><p>Leden hebben toegang tot de functies die je aan hen toewijst. Configureer hun rechten per functie.</p><h3 id="accountant" tabindex="-1">Accountant <a class="header-anchor" href="#accountant" aria-label="Permalink to &quot;Accountant&quot;">​</a></h3><p>Een speciale rol voor externe accountants:</p><ul><li>Financiele gegevens bekijken (facturen, uitgaven, rapportages)</li><li>Kan standaard geen records aanmaken of wijzigen</li><li>Specifieke rechtenset voor controledoeleinden</li></ul><h2 id="rechten" tabindex="-1">Rechten <a class="header-anchor" href="#rechten" aria-label="Permalink to &quot;Rechten&quot;">​</a></h2><p>Fijnmazige rechten stellen je in staat om toegang per functie te bepalen:</p><h3 id="paginatoegang" tabindex="-1">Paginatoegang <a class="header-anchor" href="#paginatoegang" aria-label="Permalink to &quot;Paginatoegang&quot;">​</a></h3><p>Kies welke secties elk lid kan zien:</p><ul><li>Facturen</li><li>Offertes</li><li>Uitgaven</li><li>Klanten</li><li>Projecten</li><li>Contracten</li><li>Objecten</li><li>Tijdregistratie</li><li>Rapportages</li><li>BTW</li><li>Instellingen</li></ul><h3 id="bewerkrechten" tabindex="-1">Bewerkrechten <a class="header-anchor" href="#bewerkrechten" aria-label="Permalink to &quot;Bewerkrechten&quot;">​</a></h3><p>Voor elke toegankelijke pagina kies je of het lid kan:</p><ul><li><strong>Alleen bekijken</strong> — Leestoegang, geen wijzigingen</li><li><strong>Bewerken</strong> — Volledige lees-/schrijftoegang</li></ul><h2 id="accountantcontacten" tabindex="-1">Accountantcontacten <a class="header-anchor" href="#accountantcontacten" aria-label="Permalink to &quot;Accountantcontacten&quot;">​</a></h2><p>Beheer relaties met externe accountants:</p><ol><li>Ga naar <strong>Instellingen &gt; Team &gt; Accountants</strong></li><li>Klik op <strong>Accountant toevoegen</strong></li><li>Vul hun naam en e-mailadres in</li><li>Klik op <strong>Uitnodigen</strong> om toegang te versturen</li><li>Configureer hun specifieke rechten</li></ol><h3 id="accountanttoegang-beheren" tabindex="-1">Accountanttoegang beheren <a class="header-anchor" href="#accountanttoegang-beheren" aria-label="Permalink to &quot;Accountanttoegang beheren&quot;">​</a></h3><ul><li><strong>Uitnodigen</strong> — Verstuur of verstuur de toegangsuitnodiging opnieuw</li><li><strong>Intrekken</strong> — Verwijder toegang (kan later worden hersteld)</li><li><strong>Herstellen</strong> — Eerder ingetrokken toegang opnieuw inschakelen</li><li><strong>Rechten bijwerken</strong> — Wijzig wat ze kunnen zien</li></ul><h2 id="wisselen-tussen-werkruimten" tabindex="-1">Wisselen tussen werkruimten <a class="header-anchor" href="#wisselen-tussen-werkruimten" aria-label="Permalink to &quot;Wisselen tussen werkruimten&quot;">​</a></h2><p>Als je lid bent van meerdere werkruimten (bedrijven), wissel je ertussen:</p><ol><li>Klik op je accountmenu</li><li>Selecteer <strong>Werkruimte wisselen</strong></li><li>Kies de werkruimte</li></ol><p>Of maak een <strong>nieuwe werkruimte</strong> aan vanuit hetzelfde menu.</p><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>Gebruik de accountantrol voor je boekhouder — deze biedt precies de toegang die ze nodig hebben</li><li>Stel lidrechten zorgvuldig in — niet iedereen heeft toegang nodig tot facturering of teaminstellingen</li><li>Controleer teamtoegang periodiek, vooral wanneer teamleden van rol wisselen</li></ul><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Teambeheer met meer dan 1 lid vereist het <strong>Pro</strong>-abonnement. Onbeperkte leden zijn beschikbaar met het <strong>Business</strong>-abonnement.</p></div>',35)])])}const m=n(r,[["render",l]]);export{h as __pageData,m as default};
